    requests.append({
        "custom_id": f"doc_{i}",
        "params": {
            "model": "claude-3-5-sonnet-20241022",
            "max_tokens": 512,
            "messages": [{
                "role": "user",
                "content": f"Classify this document as invoice, contract, or correspondence:\n\n{doc_text[:2000]}"
            }]
        }
    })

# Submit batch
batch = client.messages.batches.create(requests=requests)
